package ru.zinin.frigate.analyzer.telegram.bot.handler.quickexport

import io.mockk.*
import kotlinx.coroutines.test.runTest
import org.junit.jupiter.api.BeforeEach
import org.junit.jupiter.api.Test
import java.nio.file.Path
import java.util.UUID
// ... остальные импорты

class QuickExportHandlerTest {
    private lateinit var bot: TelegramBot
    private lateinit var videoExportService: VideoExportService
    private lateinit var userService: TelegramUserService
    private lateinit var properties: TelegramProperties
    private lateinit var handler: QuickExportHandler

    @BeforeEach
    fun setup() {
        bot = mockk(relaxed = true)
        videoExportService = mockk()
        userService = mockk()
        properties = mockk {
            every { owner } returns "testowner"
            every { unauthorizedMessage } returns "Unauthorized"
            every { sendVideoTimeout } returns java.time.Duration.ofMinutes(3)
        }
        handler = QuickExportHandler(bot, videoExportService, userService, properties)
    }

    @Test
    fun `should export video for authorized user`() = runTest {
        // given
        val recordingId = UUID.randomUUID()
        val callback = createMockCallback("qe:$recordingId", "testuser")
        val videoPath = Path.of("/tmp/test.mp4")

        coEvery { userService.findActiveByUsername("testuser") } returns mockk()
        coEvery { videoExportService.exportByRecordingId(recordingId, any(), any()) } returns videoPath
        coEvery { videoExportService.cleanupExportFile(videoPath) } just Runs

        // when
        handler.handle(callback)

        // then
        coVerify { bot.answer(callback) }
        coVerify { videoExportService.exportByRecordingId(recordingId, any(), any()) }
        coVerify { bot.sendVideo(any(), any()) }
        coVerify { videoExportService.cleanupExportFile(videoPath) }
    }

    @Test
    fun `should reject unauthorized user`() = runTest {
        // given
        val callback = createMockCallback("qe:${UUID.randomUUID()}", "unknownuser")
        coEvery { userService.findActiveByUsername("unknownuser") } returns null

        // when
        handler.handle(callback)

        // then
        coVerify { bot.answer(callback, "Unauthorized") }
        coVerify(exactly = 0) { videoExportService.exportByRecordingId(any(), any(), any()) }
    }

    @Test
    fun `should handle export error gracefully`() = runTest {
        // given
        val recordingId = UUID.randomUUID()
        val callback = createMockCallback("qe:$recordingId", "testowner")

        coEvery { videoExportService.exportByRecordingId(recordingId, any(), any()) } throws
            IllegalArgumentException("Recording not found")

        // when
        handler.handle(callback)

        // then
        coVerify { bot.sendTextMessage(any(), match { it.contains("не найдена") }) }
    }

    private fun createMockCallback(data: String, username: String): MessageDataCallbackQuery {
        // Создать мок callback с нужными данными
        return mockk {
            every { this@mockk.data } returns data
            every { user } returns mockk {
                every { this@mockk.username } returns mockk {
                    every { withoutAt } returns username
                }
            }
            every { message } returns mockk {
                every { chat } returns mockk {
                    every { id } returns mockk()
                }
            }
        }
    }
}
